def tc(
    n: int,
    package_id: str,
    title: str,
    priority: str,
    tc_type: str,
    goal: str,
    preconditions: list[str],
    data: list[str],
    steps: list[str],
    expected: str,
    postconditions: list[str],
    ft_link: str,
    source: list[str],
    quote: str,
    trace: str,
) -> TestCase:
    return TestCase(
        f"TC-UI-EMP-V6-{n:03d}",
        package_id,
        title,
        priority,
        tc_type,
        goal,
        preconditions,
        data,
        steps,
        expected,
        postconditions,
        ft_link,
        source,
        quote,
        trace,
    )


