def md_table(headers: list[str], rows: list[list[str]]) -> str:
    out = ["| " + " | ".join(headers) + " |", "| " + " | ".join(["---"] * len(headers)) + " |"]
    out += ["| " + " | ".join(str(cell).replace("\n", "<br>") for cell in row) + " |" for row in rows]
    return "\n".join(out)


def write_with_manifest(target: Path, sections: list[tuple[int, str, str]], preamble: str | None = None) -> None:
    target.parent.mkdir(parents=True, exist_ok=True)
    BUILD_DIR.mkdir(parents=True, exist_ok=True)
    stem = target.name.replace(".", "_")
    manifest = {"target_path": os.path.relpath(target, BUILD_DIR)}
    section_entries = []
    if preamble:
        preamble_file = BUILD_DIR / f"{stem}.preamble.md"
        preamble_file.write_text(preamble, encoding="utf-8", newline="\n")
        manifest["preamble_file"] = preamble_file.name
    for idx, (level, heading, content) in enumerate(sections, 1):
        content_file = BUILD_DIR / f"{stem}.{idx:02d}.section.txt"
        content_file.write_text(content.rstrip() + "\n", encoding="utf-8", newline="\n")
        section_entries.append({"level": level, "heading": heading, "content_file": content_file.name})
    manifest["sections"] = section_entries
    manifest_path = BUILD_DIR / f"{stem}.manifest.json"
    manifest_path.write_text(json.dumps(manifest, ensure_ascii=False, indent=2), encoding="utf-8", newline="\n")
    subprocess.run([sys.executable, str(ROOT / "scripts" / "write_artifact_sections.py"), "--manifest", str(manifest_path)], check=True, cwd=ROOT)


def artifact_write_strategy() -> str:
    return md_table(
        ["item", "value", "evidence"],
        [
            ["preflight_result", "`large-file / package-based`", "`60` planned TC; `61` ATOM rows; `WP-01..WP-04`; table-heavy source rows"],
            ["write_method", "`file-based manifest/chunked writing`", "`scripts/write_artifact_sections.py --manifest <manifest.json>`"],
            ["forbidden_methods_checked", "`yes`", "no one-shot PowerShell argument, no here-string, no inline giant command"],
            ["chunk_plan", "`instructions -> source rows -> normalization -> design artifacts -> canonical TC -> logs/state`", "one generated artifact target at a time"],
            ["helper_artifacts", "`scripts/build_ui_employment_canary_v6_writer_artifacts.py`; generated manifests under `_writer_sections/`", "committed helper with deterministic source data and file-based Markdown sections"],
            ["validation_plan", "`python scripts\\validate_agent_artifacts.py --root fts\\ft-2-OF_16 --json`", "after artifact generation and state update"],
        ],
    )


def source_row_inventory() -> str:
    return md_table(
        ["source_row_id", "package_id", "field_or_action", "source_ref", "requirement_codes", "in_scope", "mapped_atom_or_gap"],
        [[r.row_id, f"`{r.package_id}`", r.name, r.source_ref, r.req, r.scope, r.mapping] for r in SOURCE_ROWS],
    )


def source_row_completeness() -> str:
    rows = []
    for r in SOURCE_ROWS:
        props = [a.prop_id for a in ATOMS if a.source_row_id == r.row_id]
        atoms = [a.atom_id for a in ATOMS if a.source_row_id == r.row_id]
        gaps = sorted({a.gap for a in ATOMS if a.source_row_id == r.row_id and a.gap != "none"})
        if r.mapping.startswith("GAP"):
            gaps.append(r.mapping)
        rows.append([r.row_id, r.req, "; ".join(props) if props else "none", "; ".join(atoms) if atoms else "none", "; ".join(gaps) if gaps else "none", "split-complete" if props or gaps else "out-of-scope-context"])
    return md_table(["source_row_id", "source_requirement_codes", "normalized_property_ids", "linked_atoms", "gap_ids", "coverage_decision"], rows)


def normalization() -> str:
    rows = []
    for a in ATOMS:
        rows.append([a.source_row_id, a.prop_id, a.package_id, a.field, a.property_type, a.condition, a.behavior, a.req, next(r.source_ref for r in SOURCE_ROWS if r.row_id == a.source_row_id), "high", a.gap, a.atom_id])
    gap_props = [
        ("SRC-003", "SRC-003.P05", "WP-01", "Среднемесячный доход после вычета налогов", "numeric-invalid-oracle", "letters/spaces/special/decimal/sign or value below 2000", "exact UI rejection/feedback is not defined", "GSR 124", "GAP-005"),
        ("SRC-009", "SRC-009.P06", "WP-01", "Рабочий телефон", "exact-length-invalid-oracle", "9 digits, 11 digits, non-digit characters", "exact UI rejection/feedback is not defined", "GSR 133", "GAP-006"),
        ("SRC-011", "SRC-011.P04", "WP-02", "Тип дохода", "duplicate-prevention-oracle", "`Пенсия` or `Аренда` already exists in another block", "exact UI prevention mechanism is not defined", "none", "GAP-002"),
        ("SRC-016", "SRC-016.P05", "WP-03", "Параметры визуальной оценки", "clear-selection-oracle", "selected values need to be cleared", "clear/reset behavior is not defined", "GSR 139; GSR 140", "GAP-007"),
        ("SRC-018", "SRC-018.P04", "WP-04", "Редактирование из статуса `Выбор решения`", "internal-status-lifecycle", "return from status `Выбор решения` and critical field changed", "SPR/anti-fraud observable artifact is not defined", "GSR 142", "GAP-003"),
        ("SRC-018", "SRC-018.P05", "WP-04", "Заявление-анкета", "print-form-content-mapping", "print form generated", "field-to-document content mapping is not provided in this scope", "GSR 143", "GAP-008"),
    ]
    for row_id, prop_id, wp, field, prop, cond, behavior, req, gap in gap_props:
        rows.append([row_id, prop_id, wp, field, prop, cond, behavior, req, next(r.source_ref for r in SOURCE_ROWS if r.row_id == row_id), "medium", gap, "none"])
    return md_table(["source_row_id", "source_property_id", "package_id", "field_or_block", "property", "condition", "expected_behavior", "requirement_code", "source_ref", "confidence", "gap_id", "linked_atoms"], rows)


