def ledger() -> str:
    return md_table(
        ["atom_id", "package_id", "source_row_id", "source_property_id", "req_id", "atomic_statement", "coverage_status", "linked_tc_or_gap", "source_ref"],
        [[a.atom_id, a.package_id, a.source_row_id, a.prop_id, a.req, f"{a.field}: {a.behavior} при условии `{a.condition}`.", "covered" if a.tc != "none" else "gap", a.tc if a.tc != "none" else a.gap, next(r.source_ref for r in SOURCE_ROWS if r.row_id == a.source_row_id)] for a in ATOMS]
        + [[gap, "WP-01..WP-04", "multiple", f"gap:{gap}", ref, desc, "gap", gap, ref] for gap, _status, ref, desc, _handling in GAPS],
    )


def plan() -> str:
    rows = []
    for i, a in enumerate(ATOMS, 1):
        rows.append([f"PD-{i:03d}", a.package_id, a.dimension, f"{a.req}; {a.source_row_id}", a.atom_id, a.behavior, "positive" if "не " not in a.behavior and "подсвечивается" not in a.behavior else "negative", a.property_type, a.condition, a.behavior, f"{a.req}; {a.source_row_id}", a.tc, "covered"])
    for i, (gap, _status, ref, desc, handling) in enumerate(GAPS, len(rows) + 1):
        rows.append([f"PD-{i:03d}", "WP-01..WP-04", "gap", ref, gap, handling, "gap", "unresolved-oracle", "source-backed invariant with missing deterministic mechanism/setup", desc, gap, gap, "gap"])
    return md_table(["design_item_id", "package_id", "design_dimension", "source_ref", "linked_atoms", "planned_check", "check_type", "coverage_class", "input_class", "single_expected_behavior", "oracle_source", "planned_tc_or_gap", "status"], rows)


def tc_markdown(t: TestCase) -> str:
    def bullets(items: list[str]) -> str:
        return "\n".join(f"- {x}" for x in items)
    steps = "\n".join(f"{i}. {x}" for i, x in enumerate(t.steps, 1))
    return f"""## {t.tc_id}
**Название:** {t.title}
**Приоритет:** {t.priority}
**Тип:** {t.tc_type}
**package_id:** `{t.package_id}`

**Цель:** {t.goal}

**Предусловия:**
{bullets(t.preconditions)}

**Тестовые данные:**
{bullets(t.data)}

**Шаги:**
{steps}

**Итоговый ожидаемый результат:** {t.expected}

**Постусловия:**
{bullets(t.postconditions)}

**Трассировка:** {t.trace}

**Ссылка на ФТ:** {t.ft_link}

**Источник требования:**
{bullets(t.source)}

**Источник / цитата требования:** {t.quote}
"""


def canonical() -> str:
    links = [
        "artifact-write-strategy.md",
        "mockup-usage.md",
        "source-row-inventory.md",
        "source-row-completeness-matrix.md",
        "source-table-normalization.md",
        "dictionary-inventory.md",
        "test-design-decision-table.md",
        "coverage-obligation-table.md",
        "atomic-requirements-ledger.md",
        "package-test-design-plan.md",
        "coverage-gaps.md",
        "writer-quality-gate.md",
        "writer-self-check.md",
    ]
    summary = md_table(
        ["item", "value"],
        [
            ["ft_slug", "`ft-2-OF_16`"],
            ["scope_slug", f"`{SCOPE}`"],
            ["writer_mode", "`fresh-eval-run / session_initial_draft`"],
            ["canonical_file", f"`test-cases/{CANONICAL.name}`"],
            ["test_design_dir", f"`work/test-design/{SCOPE}/`"],
            ["coverage_boundary", "`SRC-002`-`SRC-021` selected by v6 prompt; `SRC-022`-`SRC-024` only residual `GAP-004` context"],
            ["residual_gaps", "`GAP-001`; `GAP-002`; `GAP-003`; `GAP-004`; `GAP-005`; `GAP-006`; `GAP-007`; `GAP-008`"],
        ],
    )
    artifact_links = "\n".join(f"- `work/test-design/{SCOPE}/{x}`" for x in links)
    groups: dict[str, list[TestCase]] = {}
    for t in TEST_CASES:
        groups.setdefault(t.package_id, []).append(t)
    package_names = {
        "WP-01": "Тип занятости, основная работа, работодатель, адрес, должность, стаж и телефон",
        "WP-02": "Дополнительный доход",
        "WP-03": "Общие поля и визуальная оценка",
        "WP-04": "Действия раздела",
    }
    body = [summary, "### Canonical Artifact Links\n\n" + artifact_links]
    for package_id in ["WP-01", "WP-02", "WP-03", "WP-04"]:
        body.append(f"## {package_id}. {package_names[package_id]}\n\n" + "\n\n".join(tc_markdown(t).rstrip() for t in groups[package_id]))
    return "\n\n".join(body)


def coverage_gaps() -> str:
    return md_table(["gap_id", "status", "source_ref", "missing_behavior", "writer_handling"], [list(g) for g in GAPS])


def simple_artifact(title: str, table: str) -> str:
    return table


